  "description": "A simple project management API",
  "main": "src/app.js",
  "scripts": {
    "start": "node src/server.js",
    "test": "node --test tests/oracle.test.js"
  },
  "dependencies": {
    "express": "^4.18.2"
  },
  "devDependencies": {
    "supertest": "^6.3.3"
  }
}

const crypto = require('node:crypto');

function generateId() {
  return crypto.randomUUID();
}

module.exports = { generateId };

function createError(code, message) {
  const error = new Error(message);
  error.code = code;
  return error;
}

module.exports = { createError };
